import{_ as o,o as e,c as a,a2 as i}from"./chunks/framework.C2B0glpm.js";const p=JSON.parse('{"title":"Finestra di contesto","description":"","frontmatter":{},"headers":[],"relativePath":"it/utilizzo/finestra-contesto.md","filePath":"it/utilizzo/finestra-contesto.md"}'),n={name:"it/utilizzo/finestra-contesto.md"};function l(r,t,s,c,d,u){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="finestra-di-contesto" tabindex="-1">Finestra di contesto <a class="header-anchor" href="#finestra-di-contesto" aria-label="Permalink to &quot;Finestra di contesto&quot;">​</a></h1><p>Gestisci la finestra di contesto e la lunghezza della conversazione.</p><p>TurboDev traccia l&#39;utilizzo dei token in tempo reale e lo mostra nella barra di stato. Quando la finestra di contesto si riempie, l&#39;auto-compattazione mantiene la conversazione attiva.</p><h2 id="utilizzo-token" tabindex="-1">Utilizzo token <a class="header-anchor" href="#utilizzo-token" aria-label="Permalink to &quot;Utilizzo token&quot;">​</a></h2><p>La barra di stato mostra un indicatore dei token come <code>1.24K/128K</code>:</p><ul><li><strong>Valore a sinistra</strong> — Token stimati utilizzati (inclusi prompt di sistema, cronologia e risultati degli strumenti)</li><li><strong>Valore a destra</strong> — Lunghezza massima del contesto per il modello corrente</li></ul><h3 id="codifica-colore" tabindex="-1">Codifica colore <a class="header-anchor" href="#codifica-colore" aria-label="Permalink to &quot;Codifica colore&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Colore</th><th>Utilizzo</th><th>Comportamento</th></tr></thead><tbody><tr><td>Verde</td><td>Sotto il 50%</td><td>Funzionamento normale</td></tr><tr><td>Giallo</td><td>50%–75%</td><td>Avviso — considera la compattazione</td></tr><tr><td>Rosso</td><td>Sopra il 75%</td><td>Auto-compattazione al 85%</td></tr></tbody></table><h2 id="auto-compattazione" tabindex="-1">Auto-compattazione <a class="header-anchor" href="#auto-compattazione" aria-label="Permalink to &quot;Auto-compattazione&quot;">​</a></h2><p>Quando l&#39;utilizzo dei token raggiunge il <strong>75%</strong>, TurboDev ti notifica. All&#39;<strong>85%</strong>, la conversazione viene compattata automaticamente:</p><ol><li>L&#39;intera conversazione viene inviata all&#39;LLM</li><li>L&#39;LLM genera un riassunto conciso</li><li>La conversazione viene sostituita con il riassunto</li><li>Puoi continuare a chattare normalmente</li></ol><p>Il riassunto preserva le decisioni chiave, le modifiche al codice e il contesto necessario per il compito in corso.</p><h2 id="compattazione-manuale" tabindex="-1">Compattazione manuale <a class="header-anchor" href="#compattazione-manuale" aria-label="Permalink to &quot;Compattazione manuale&quot;">​</a></h2><p>Usa <code>/compact</code> in qualsiasi momento per attivare manualmente la compattazione:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact</span></span></code></pre></div><p>Utile quando:</p><ul><li>Vuoi liberare contesto prima di un compito complesso</li><li>La conversazione è deviata e vuoi ripartire pulito</li><li>Stai per raggiungere il limite di contesto e vuoi compattare quando preferisci</li></ul><h2 id="come-vengono-contati-i-token" tabindex="-1">Come vengono contati i token <a class="header-anchor" href="#come-vengono-contati-i-token" aria-label="Permalink to &quot;Come vengono contati i token&quot;">​</a></h2><p>TurboDev stima i token a circa <strong>4 caratteri per token</strong>. È un&#39;approssimazione vicina per la maggior parte dei modelli LLM. Il conteggio include:</p><ul><li><strong>Prompt di sistema</strong> — Istruzioni dell&#39;agente, definizioni degli strumenti, contenuto di AGENTS.md</li><li><strong>Cronologia della conversazione</strong> — Tutti i messaggi utente e assistente</li><li><strong>Risultati degli strumenti</strong> — Output da letture di file, comandi bash, ecc.</li></ul><p>Il conteggio dei token viene mostrato immediatamente all&#39;avvio (solo prompt di sistema) e aggiornato dopo ogni scambio di messaggi.</p><h2 id="tracciamento-dei-costi" tabindex="-1">Tracciamento dei costi <a class="header-anchor" href="#tracciamento-dei-costi" aria-label="Permalink to &quot;Tracciamento dei costi&quot;">​</a></h2><p>TurboDev recupera il prezzo per token da OpenRouter e calcola il costo in tempo reale:</p><ul><li><strong>Token di input</strong> — Token inviati al modello (prompt di sistema + cronologia + nuovo messaggio)</li><li><strong>Token di output</strong> — Token generati dal modello (risposta)</li><li><strong>Formula del costo</strong> — <code>(tokenInput × prezzoPrompt) + (tokenOutput × prezzoCompletamento)</code></li></ul><p>Il costo cumulativo viene mostrato nella barra di stato (es. <code>$0.0023</code>) e salvato con la sessione.</p><h2 id="torna-all-utilizzo" tabindex="-1">Torna all&#39;utilizzo <a class="header-anchor" href="#torna-all-utilizzo" aria-label="Permalink to &quot;Torna all&#39;utilizzo&quot;">​</a></h2><ul><li><a href="/TurboDev/it/utilizzo/">Interfaccia terminale</a></li><li><a href="/TurboDev/it/utilizzo/comandi.html">Comandi</a></li></ul>',27)])])}const z=o(n,[["render",l]]);export{p as __pageData,z as default};
